def gen(rng, size):
    n = max(1, min(size, 100))
    if rng.random() < 0.5:
        matrix = [[((i + j) % n) + 1 for j in range(n)] for i in range(n)]
        rng.shuffle(matrix)
    else:
        matrix = [[rng.randint(1, n) for _ in range(n)] for _ in range(n)]
    return [matrix]

