class Solution:
    def checkValid(self, matrix):
        n = len(matrix)
        for row in matrix:
            seen = [False] * (n + 1)
            for v in row:
                if v < 1 or v > n or seen[v]:
                    return False
                seen[v] = True
        for j in range(n):
            seen = [False] * (n + 1)
            for i in range(n):
                v = matrix[i][j]
                if v < 1 or v > n or seen[v]:
                    return False
                seen[v] = True
        return True

