class Solution:
    def checkValid(self, matrix):
        n = len(matrix)
        full = set(range(1, n + 1))
        for row in matrix:
            if set(row) != full:
                return False
        for j in range(n):
            col = {matrix[i][j] for i in range(n)}
            if col != full:
                return False
        return True

